html:
{% set color = "#9B1B9E" %}

{% set sales_order_number = "" %}
{% if doc.items and doc.items|length > 0 %}
    {% set sales_order_number = doc.items[0].sales_order or "" %}
{% endif %}
<style>
    .print-format th {
        background-color: {{color}} !important;
        color: #ffffff !important;
    }

    .brand-color {
        color: {{color}} !important;
    }

#background{
    position:absolute;
    z-index:0;
    background:white;
    display:block;
    min-height:50%; 
    min-width:50%;
    color:yellow;
    margin:0 auto;
    text-align:center;
    margin-left:80px;
    margin-top:120px;
}

#content{
    position:absolute;
    z-index:1;
}

#bg-text
{
    color:lightgrey;
    font-size:50px;
    transform:rotate(300deg);
    -webkit-transform:rotate(300deg);
}
</style>

{% if doc.submitted %}
<!--<div id="background">-->

<!--  <p id="bg-text">Duplicate</p>-->
<!--</div>-->
<!--<div id="content">-->

{% endif %}

<table style="width:100%; margin-bottom: 20px;">
    <tr>
        <td style="width:20%; vertical-align: top;">
            {% set company_letter = frappe.db.get_value("Company", doc.company, "default_letter_head") or 'Default' %}
            <img src="{{ frappe.db.get_value('Letter Head', company_letter, 'image')}}" class="img-fluid" style="height:60px">
        </td>
        <td style="width:60%; text-align:center; vertical-align: middle;">
            <div style="color: #800080; font-weight: bold; font-size: 18px; margin-bottom: 10px;">
                {{ doc.company }}
            </div>
            <div style="color: #800080; font-weight: bold; line-height: 1.6;">
                Tel: 0615444776 / 0614000074 / 0614931894<br>
                Mogadishu Somalia
            </div>
        </td>
        <td style="width:20%; text-align:right; vertical-align: top;">
            <div style="display: inline-block;">
                <img src='/files/barcodes/QRCode{{ doc.name|replace("#","%23") }}.svg' style="width:80px; height:80px;">
            </div>
        </td>
    </tr>
</table>

<table style="width:100%; margin-bottom: 20px;">

    <tr style="padding:0px; margin:0px">
        <td style="padding:0px; margin:0px;"> 
                    <div class="" style="margin-bottom: 8px; color: #800080;font-size:20px; font-weight:700; padding-bottom: 10px;"><b>FAAHFAAHIN</b></div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>MAGACA MILKIILAHA: </b>{{doc.customer_name}}</div>

            {% set party = doc.customer %}
            {% set balance = 0 %}

            {% set query = frappe.db.get_all("GL Entry", filters={"party_type": 'Customer', "party": doc.customer, "posting_date": ("<=", doc.posting_date)},
            fields=["SUM(debit_in_account_currency) - SUM(credit_in_account_currency) as closing"]) %}

            {% if query %}
                {% set balance = query[0].closing %}
            {% endif %}

            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Phone:</b> {{doc.contact_mobile or doc.contact_phone or ""}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Model:</b> {{doc.custom_model or ""}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Color:</b> {{doc.custom_color or ""}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Chassis No:</b> {{doc.custom_chassis_no or ""}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Engine No:</b> {{ doc.custom_engine}}</div>

        </td>
        <td style="text-align: right;"> 
        <div style="text-align: right; font-size:20px; font-weight:700; padding-bottom: 10px; color: #800080;">INVOICE</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Username:</b> {{ frappe.db.get_value("User", doc.owner, "username") }}</div>
            {% set sales_person_name = "" %}
            {% set sales_contributions = frappe.db.get_all("Sales Team", filters={"parent": doc.name, "parenttype": "Sales Invoice"}, fields=["sales_person"], order_by="idx asc", limit=1) %}
            {% if sales_contributions and sales_contributions|length > 0 %}
                {% set sales_person_name = sales_contributions[0].sales_person %}
            {% endif %}
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Invoice No:</b> {{doc.name}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Date:</b> {{doc.get_formatted("posting_date")}}</div>
             <div class="" style="margin-bottom: 8px; color: #800080;"><b>RV No#:</b> {{sales_order_number}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>Assembled by:</b> {{sales_person_name}}</div>
            <div class="" style="margin-bottom: 8px; color: #800080;"><b>VAT:</b> {{doc.get_formatted("total_taxes_and_charges")}}</div>
        </td>
    </tr>
</table>

<div class="" style="margin-top: 15px; margin-bottom: 15px;">
    <table class="custom_print" style="width:100%"> 
        <thead> 
            <tr> 
                <th style="width:1%; background-color: #800080; color: #ffffff;">No</th>
                <th style="width:35%; background-color: #800080; color: #ffffff;">Item Name</th>
                <th style="width:10%; background-color: #800080; color: #ffffff;" class="text-right">Qty</th>
                <th style="width:12%; background-color: #800080; color: #ffffff;" class="text-right">Rate</th>
                <th style="width:13%; background-color: #800080; color: #ffffff;" class="text-right">Amount</th>
            </tr>
        </thead>
        {% for i in doc.items %}
        <tr style="color: #800080;font-size:12px">
            <td style="border-bottom: 1px solid; font-size: 12px; padding: 5px !important; color: #800080;">{{i.idx}}</td>
            <td style="border-bottom: 1px solid; font-size: 12px; padding: 5px !important; color: #800080;"><b>{{i.item_name}}</b></td>
            <td style="border-bottom: 1px solid; font-size: 12px; padding: 5px !important; color: #800080;" class="text-right">{{i.qty}}</td>
            <td style="border-bottom: 1px solid; font-size: 12px; padding: 5px !important; color: #800080;" class="text-right">{{i.get_formatted("rate")}}</td>
            <td style="border-bottom: 1px solid; font-size: 12px; padding: 5px !important; color: #800080;" class="text-right">{{i.get_formatted("amount")}}</td>
        </tr>
        {% endfor %}
    </table>
</div>

<table style="width:100%">
    <tr>
        <td style="font-size: 10px; color: #800080;">
            <b>Printed On: {{ frappe.utils.now_datetime().strftime("%a %d-%b-%Y %I:%M") }}</b>
        </td>
        <td style="text-align:right; font-size: 10px; color: #800080;">
            {% set username = frappe.db.get_value("User", frappe.session.user, "username") %}
            <b>Printed by: {{ username }}</b>
        </td>
    </tr>
</table>

{% if doc.submitted %}
<!--</div>-->
{% endif %}
